	dto.MetricType_GAUGE_HISTOGRAM,
	dto.MetricType_SUMMARY,
	dto.MetricType_UNTYPED:
	// All good.
default:
	return EntryInvalid, fmt.Errorf("unknown metric type for metric %q: %s", name, p.dec.GetType())
}
p.entryBytes.Reset()
p.entryBytes.WriteString(name)

